void MRFMountingHoleDlg::SetMultiListTitle()
{
	if (_pMultiListSegLefRightValues)
	{
		CATUnicodeString header[4];
		header[0] = "Tread Shoe Plane";
		header[1] = "Left Angle";
		header[2] = "Right Angle";
		header[3] = "Status";

		_pMultiListSegLefRightValues->SetColumnTitles(4,header);

		for (int i = 0; i < 4; i++)
		{
			if(i==0)
			_pMultiListSegLefRightValues->SetColumnTextWidth(i, 15);
			else if(i == 3)
			_pMultiListSegLefRightValues->SetColumnTextWidth(i, 5);
			else
				_pMultiListSegLefRightValues->SetColumnTextWidth(i, 8);

		}

	}
}

void MRFMountingHoleDlg::UpdateSelectorList(CATString strAction, CATUnicodeString aliasNameToSet)
{
	CATDlgSelectorList *pSelectorList_actual = NULL, *pSelectorListNext = NULL;
	if (strAction == FromSegmentSeletor)
	{
		pSelectorListNext = _pSelListBackProfSurf;
		pSelectorList_actual =  _pSelListSegCutSet;
	}
	else if (strAction == FromBackProfSeletor)
	{
		pSelectorListNext = _pSelListBackLiftHoleRefSurf; 
		pSelectorList_actual = _pSelListBackProfSurf;
	}
	else if (strAction == FromLiftingHoleRefSurfSeletor)
	{
		pSelectorList_actual = _pSelListBackLiftHoleRefSurf;
		pSelectorListNext = _pSelListBackLiftHoleRefSurf;
	}

	if(strAction != FromLiftingHoleRefSurfSeletor)
		pSelectorList_actual->ClearLine();
	else
	{
		CATUnicodeString nameToCheck = "No Lifting Surface Selected", nameOfLineAtZeroIndex;
		pSelectorList_actual->GetLine(nameOfLineAtZeroIndex, 0);
		if (nameToCheck.Compare(nameOfLineAtZeroIndex))
		{
			int row[] = { 0 };
			pSelectorList_actual->ClearLine(row, 1);
		}
	}

	pSelectorList_actual->SetLine(aliasNameToSet,-1,CATDlgDataAdd);

	int select = 0;
	pSelectorListNext->SetSelect(&select, 1);
}

void MRFMountingHoleDlg::ClearOtherSelections(CATString strAction)
{
	if (strAction == FromSegmentSeletor)
	{
		_pSelListBackProfSurf->ClearSelect();
		_pSelListBackLiftHoleRefSurf->ClearSelect();
		_pComboMountHolePlacementType->ClearSelect();
	}
	else if (strAction == FromBackProfSeletor)
	{
		_pSelListSegCutSet->ClearSelect();
		_pSelListBackLiftHoleRefSurf->ClearSelect();
		_pComboMountHolePlacementType->ClearSelect();
	}
	else if (strAction == FromLiftingHoleRefSurfSeletor)
	{
		_pSelListSegCutSet->ClearSelect();
		_pSelListBackProfSurf->ClearSelect();
		_pComboMountHolePlacementType->ClearSelect();
	}

}

